using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- Setup: use the default reflection-based resolver for known types ---
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// ========================================================================
// 1. GetTypeInfo<T>() – strongly-typed access (returns JsonTypeInfo<T>)
// ========================================================================
JsonTypeInfo<Person> personMeta = options.GetTypeInfo<Person>();
Console.WriteLine($"Typed metadata for Person: {personMeta.Type.Name}");
Console.WriteLine($"  Kind       : {personMeta.Kind}");
Console.WriteLine($"  Properties : {personMeta.Properties.Count}");

// ========================================================================
// 2. TryGetTypeInfo – probe without throwing
//    Returns false (and null) when metadata is unavailable for the type.
// ========================================================================

// 2a. Type that IS resolvable
bool found = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info);
Console.WriteLine($"\nTryGetTypeInfo(Person) => found={found}, info is null={info is null}");

// 2b. Type that is NOT resolvable (use a custom resolver that resolves nothing)
var restrictedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = new EmptyResolver()
};

bool foundWidget = restrictedOptions.TryGetTypeInfo(typeof(Widget), out JsonTypeInfo? widgetInfo);
Console.WriteLine($"TryGetTypeInfo(Widget) => found={foundWidget}, info is null={widgetInfo is null}");
Console.WriteLine("\nDone – no exceptions thrown.");

// ----- Types used in the demo -----
public record Person(string Name, int Age);
public record Widget(string Id);

// A resolver that never resolves anything – simulates "metadata not available"
file class EmptyResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) => null;
}

